using BgControls.Windows.Controls.DragDrop.NativeWrappers;namespace BgControls.Windows.Controls.DragDrop;/// <summary>/// 无法被检测到的透明辅助窗口类，通常用于拖拽指示器的承载./// </summary>internal class UndetectableWindow : Window, IDisposable{    /// <summary>    /// 窗口句柄缓存.    /// </summary>    private IntPtr windowHandle;    /// <summary>    /// 父窗口引用.    /// </summary>    private Window? parentWindow;    /// <summary>    /// 当前视觉提示显示行为.    /// </summary>    private VisualCueBehavior currentDisplayBehavior;    /// <summary>    /// 窗口是否已打开的内部标志.    /// </summary>    private bool isOpen;    /// <summary>    /// Initializes a new instance of the <see cref="UndetectableWindow"/> class.    /// </summary>    /// <param name="parentVisual">父框架元素.</param>    public UndetectableWindow(FrameworkElement parentVisual)        : this(parentVisual as Window)    {        // 验证父元素是否为空.        ArgumentNullException.ThrowIfNull(parentVisual, nameof(parentVisual));        // 设置父级视觉对象并绑定卸载事件.        this.ParentVisual = parentVisual;        this.ParentVisual.Unloaded += this.OnParentElementUnloaded;    }    /// <summary>    /// Initializes a new instance of the <see cref="UndetectableWindow"/> class.    /// </summary>    /// <param name="parentWindow">可选的父窗口对象.</param>    public UndetectableWindow(Window? parentWindow)    {        // 配置窗口基础样式以实现透明与无边框效果.        this.WindowStyle = WindowStyle.None;        this.AllowsTransparency = true;        this.Background = Brushes.Transparent;        this.ShowInTaskbar = false;        this.WindowState = WindowState.Normal;        this.HorizontalAlignment = HorizontalAlignment.Left;        this.VerticalAlignment = VerticalAlignment.Top;        this.IsHitTestVisible = false;        this.Focusable = false;        this.Topmost = true;        if (parentWindow != null)        {            this.ParentWindow = parentWindow;        }        this.Loaded += this.OnUndetectableWindowLoaded;    }    /// <summary>    /// Gets or sets a value indicating whether 是否根据子元素尺寸自动调整窗口大小.    /// </summary>    public bool FitToChildDimensions { get; set; }    /// <summary>    /// Gets 窗口的句柄.    /// </summary>    private IntPtr WindowHandle    {        get        {            // 如果句柄尚未初始化，则通过助手类获取.            if (this.windowHandle == IntPtr.Zero)            {                this.windowHandle = new WindowInteropHelper(this).Handle;            }            return this.windowHandle;        }    }    /// <summary>    /// Gets a value indicating whether 资源是否已被释放.    /// </summary>    internal bool Disposed { get; private set; }    /// <summary>    /// Gets or sets 父级视觉对象.    /// </summary>    private FrameworkElement? ParentVisual { get; set; }    /// <summary>    /// Gets or sets 父窗口对象.    /// </summary>    internal Window? ParentWindow    {        get        {            return this.parentWindow;        }        set        {            // 处理父窗口变更及事件订阅.            if (this.parentWindow != value && value != null)            {                if (this.parentWindow != null)                {                    this.parentWindow.Closing -= this.OnParentWindowClosing;                }                this.parentWindow = value;                this.parentWindow.Closing += this.OnParentWindowClosing;                this.parentWindow.Unloaded += this.OnParentWindow_Unloaded;            }        }    }    /// <summary>    /// Gets or sets 窗口承载的子元素内容.    /// </summary>    public FrameworkElement? Child    {        get        {            return this.Content as FrameworkElement;        }        set        {            if (this.Content != value)            {                // 更换内容时同步处理事件订阅.                this.UnsubscribeFromChildEvents();                this.Content = value;                this.SubscribeToChildEvents();            }        }    }    /// <summary>    /// Gets or sets 自动关闭窗口的判定条件委托.    /// </summary>    internal Func<bool>? AutoCloseCondition { get; set; }    /// <summary>    /// Gets or sets 当前视觉提示的显示行为.    /// </summary>    public VisualCueBehavior CurrentDisplayBehavior    {        get        {            return this.currentDisplayBehavior;        }        set        {            // 若行为设置为保持位置，则激活所有者窗口.            if (this.Owner != null && value == VisualCueBehavior.KeepCurrentPosition)            {                this.Owner.Activate();            }            this.currentDisplayBehavior = value;        }    }    /// <summary>    /// Gets a value indicating whether 窗口是否不应被激活.    /// </summary>    public bool ShouldNotBeActivated => this.CurrentDisplayBehavior == VisualCueBehavior.KeepCurrentPosition;    /// <summary>    /// Gets or sets 垂直偏移量.    /// </summary>    public double VerticalOffset { get; set; }    /// <summary>    /// Gets or sets 水平偏移量.    /// </summary>    public double HorizontalOffset { get; set; }    /// <summary>    /// Gets or sets a value indicating whether 窗口是否处于打开状态.    /// </summary>    public bool IsOpen    {        get        {            return this.isOpen;        }        set        {            if (this.isOpen != value)            {                this.isOpen = value;                this.UpdateIsOpen();            }        }    }    /// <summary>    /// 取消订阅子元素的相关事件.    /// </summary>    private void UnsubscribeFromChildEvents()    {        if (this.Child != null)        {            this.Child.Loaded -= this.OnChildLoaded;        }    }    /// <summary>    /// 订阅子元素的相关事件.    /// </summary>    private void SubscribeToChildEvents()    {        if (this.Child != null)        {            this.Child.Loaded += this.OnChildLoaded;        }    }    /// <summary>    /// 当子元素加载完成时触发.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnChildLoaded(object sender, RoutedEventArgs e)    {        // 若启用了尺寸适配，则在布局更新时调整窗口大小.        if (this.FitToChildDimensions)        {            this.InvalidateMeasure();            this.LayoutUpdated += this.OnLayoutUpdated;        }    }    /// <summary>    /// 当布局完成更新时调整窗口物理尺寸.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnLayoutUpdated(object? sender, EventArgs e)    {        if (this.Child != null && this.Child.IsLoaded)        {            // 只执行一次布局自适应.            this.LayoutUpdated -= this.OnLayoutUpdated;            this.Width = this.Child.DesiredSize.Width;            this.Height = this.Child.DesiredSize.Height;            this.Opacity = 1.0;        }    }    /// <summary>    /// 预处理窗口尺寸，为自适应布局准备初始状态.    /// </summary>    private void EnsureAutoFitSize()    {        if (this.FitToChildDimensions)        {            if (this.Child != null)            {                // 先隐藏再测量，防止闪烁.                this.Opacity = 0.0;                this.Height = SystemParameters.PrimaryScreenHeight;                this.Width = SystemParameters.PrimaryScreenWidth;            }            else            {                this.Height = 0.0;                this.Width = 0.0;            }        }    }    /// <summary>    /// 强制子元素按照给定尺寸进行排列.    /// </summary>    /// <param name="size">排列的目标尺寸.</param>    private void EnsureAutoFitArrange(Size size)    {        if (this.FitToChildDimensions && this.Child != null)        {            this.Child.Arrange(new Rect(size));        }    }    /// <summary>    /// 测量子元素的期望尺寸.    /// </summary>    /// <param name="resultSize">可用的参考尺寸.</param>    private void EnsureAutoFitMeasure(Size resultSize)    {        if (this.Child != null && this.Child.IsLoaded && this.FitToChildDimensions)        {            this.Child.Measure(resultSize);        }    }    /// <summary>    /// 当父窗口从视觉树中移除时触发.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnParentWindow_Unloaded(object sender, RoutedEventArgs e)    {        if (this.ParentWindow != null)        {            this.ParentWindow.Unloaded -= this.OnParentWindow_Unloaded;        }        // 检查自动关闭条件并执行释放.        if (this.AutoCloseCondition != null && this.AutoCloseCondition())        {            this.Dispose();        }    }    /// <summary>    /// 判定给定的线程是否是当前窗口的调度线程.    /// </summary>    /// <param name="thread">待检查的线程对象.</param>    /// <returns>如果是同一线程则返回 true.</returns>    internal bool CanManage(System.Threading.Thread thread)    {        return this.Dispatcher.Thread.ManagedThreadId == thread.ManagedThreadId;    }    /// <summary>    /// 当窗口被激活时执行逻辑，确保不干扰父窗口的焦点.    /// </summary>    /// <param name="e">事件数据.</param>    protected override void OnActivated(EventArgs e)    {        base.OnActivated(e);        if (this.ParentWindow != null && this.ShouldNotBeActivated)        {            this.ParentWindow.Activate();        }    }    /// <summary>    /// 当窗口内容发生变更时触发.    /// </summary>    /// <param name="oldContent">旧内容.</param>    /// <param name="newContent">新内容.</param>    protected override void OnContentChanged(object oldContent, object newContent)    {        this.EnsureAutoFitSize();        base.OnContentChanged(oldContent, newContent);    }    /// <summary>    /// 当窗口加载时设置底层 Win32 透明样式.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">事件参数.</param>    private void OnUndetectableWindowLoaded(object sender, RoutedEventArgs e)    {        // 通过原生包装器设置窗口穿透与透明.        NativeWindowStyleWrapper.SetTransparentStyle(sender as Window);    }    /// <summary>    /// 根据当前打开状态显示或隐藏窗口.    /// </summary>    private void UpdateIsOpen()    {        if (this.IsOpen)        {            this.Show();        }        else        {            this.Hide();        }    }    /// <summary>    /// 更新窗口在屏幕上的物理位置.    /// </summary>    /// <param name="refresh">是否强制刷新.</param>    public void UpdatePosition(bool refresh)    {        this.UpdatePosition(refresh, this.Width, this.Height);    }    /// <summary>    /// 更新窗口在屏幕上的物理位置及尺寸.    /// </summary>    /// <param name="refresh">是否强制刷新.</param>    /// <param name="width">目标宽度.</param>    /// <param name="height">目标高度.</param>    public void UpdatePosition(bool refresh, double width, double height)    {        // 判定位置是否发生显著变化，以减少不必要的系统调用.        bool isVerticalChanged = Math.Abs(this.Top - this.VerticalOffset) >= 1.0 || double.IsNaN(this.Top);        bool isHorizontalChanged = Math.Abs(this.Left - this.HorizontalOffset) >= 1.0 || double.IsNaN(this.Left);        if (isVerticalChanged || isHorizontalChanged)        {            // 通过 Win32 API 移动窗口.            WindowPositionWrapper.MoveWindow(this.WindowHandle, (int)this.HorizontalOffset, (int)this.VerticalOffset, (int)width, (int)height, refresh);        }    }    /// <summary>    /// 测量窗口所需尺寸.    /// </summary>    /// <param name="availableSize">可用尺寸限制.</param>    /// <returns>窗口期望的尺寸.</returns>    protected override Size MeasureOverride(Size availableSize)    {        Size result = base.MeasureOverride(availableSize);        if (!this.IsOpen)        {            result = Size.Empty;        }        else        {            this.EnsureAutoFitMeasure(result);        }        return result;    }    /// <summary>    /// 安排窗口子元素的位置.    /// </summary>    /// <param name="arrangeBounds">安排的区域界限.</param>    /// <returns>实际占用的尺寸.</returns>    protected override Size ArrangeOverride(Size arrangeBounds)    {        Size result = base.ArrangeOverride(arrangeBounds);        this.EnsureAutoFitArrange(result);        if (this.IsOpen)        {            return result;        }        return Size.Empty;    }    /// <summary>    /// 当父窗口正在关闭时同步关闭当前辅助窗口.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="e">取消事件参数.</param>    private void OnParentWindowClosing(object? sender, CancelEventArgs e)    {        if (this.ParentWindow != null)        {            this.ParentWindow.Closing -= this.OnParentWindowClosing;        }        if (this.AutoCloseCondition != null && this.AutoCloseCondition())        {            this.Dispose();        }    }    /// <summary>    /// 当父视觉元素卸载时关闭并释放资源.    /// </summary>    /// <param name="sender">事件源.</param>    /// <param name="args">事件参数.</param>    private void OnParentElementUnloaded(object sender, RoutedEventArgs args)    {        if (this.ParentVisual != null)        {            this.ParentVisual.Unloaded -= this.OnParentElementUnloaded;        }        this.Dispose();    }    /// <summary>    /// 释放窗口占用的所有资源并关闭窗口.    /// </summary>    public void Dispose()    {        this.ParentWindow = null;        this.ParentVisual = null;        this.IsOpen = false;        this.Close();        this.Disposed = true;    }}